create type "public"."prepackaged_dataset_kind" as enum ('vector', 'tiles', 'labels', 'satellite');

create type "public"."prepackaged_dataset_version_status" as enum ('draft', 'available', 'deprecated');

create table "public"."prepackaged_dataset_definitions" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "updated_at" timestamp with time zone not null default now(),
    "slug" text not null,
    "title" text not null,
    "summary" text not null,
    "description" text,
    "kind" prepackaged_dataset_kind not null,
    "is_active" boolean not null default true,
    "sort_order" integer not null default 0
);

alter table "public"."prepackaged_dataset_definitions" enable row level security;

create table "public"."prepackaged_dataset_versions" (
    "id" bigint generated by default as identity not null,
    "definition_id" bigint not null,
    "created_at" timestamp with time zone not null default now(),
    "built_at" timestamp with time zone,
    "published_at" timestamp with time zone,
    "version" text not null,
    "status" prepackaged_dataset_version_status not null default 'draft',
    "file_name" text not null,
    "storage_path" text not null,
    "public_download_path" text not null,
    "size_bytes" bigint not null,
    "checksum_sha256" text,
    "dataset_count" integer,
    "artifact_count" integer,
    "manifest" jsonb not null default '{}'::jsonb,
    "known_issues" text
);

alter table "public"."prepackaged_dataset_versions" enable row level security;

create table "public"."prepackaged_dataset_download_grants" (
    "id" uuid not null default gen_random_uuid(),
    "created_at" timestamp with time zone not null default now(),
    "expires_at" timestamp with time zone not null,
    "last_validated_at" timestamp with time zone,
    "revoked_at" timestamp with time zone,
    "version_id" bigint not null,
    "user_id" uuid not null,
    "token_hash" text not null,
    "requested_ip" inet,
    "requested_user_agent" text,
    "validation_count" integer not null default 0,
    "extra" jsonb not null default '{}'::jsonb
);

alter table "public"."prepackaged_dataset_download_grants" enable row level security;

CREATE UNIQUE INDEX prepackaged_dataset_definitions_pkey ON public.prepackaged_dataset_definitions USING btree (id);
CREATE UNIQUE INDEX prepackaged_dataset_definitions_slug_key ON public.prepackaged_dataset_definitions USING btree (slug);
CREATE UNIQUE INDEX prepackaged_dataset_versions_pkey ON public.prepackaged_dataset_versions USING btree (id);
CREATE UNIQUE INDEX prepackaged_dataset_versions_definition_version_key ON public.prepackaged_dataset_versions USING btree (definition_id, version);
CREATE UNIQUE INDEX prepackaged_dataset_download_grants_pkey ON public.prepackaged_dataset_download_grants USING btree (id);
CREATE UNIQUE INDEX prepackaged_dataset_download_grants_token_hash_key ON public.prepackaged_dataset_download_grants USING btree (token_hash);
CREATE INDEX prepackaged_dataset_versions_status_idx ON public.prepackaged_dataset_versions USING btree (status, definition_id);
CREATE INDEX prepackaged_dataset_download_grants_user_created_idx ON public.prepackaged_dataset_download_grants USING btree (user_id, created_at desc);
CREATE INDEX prepackaged_dataset_download_grants_version_created_idx ON public.prepackaged_dataset_download_grants USING btree (version_id, created_at desc);
CREATE INDEX prepackaged_dataset_download_grants_expires_idx ON public.prepackaged_dataset_download_grants USING btree (expires_at);

alter table "public"."prepackaged_dataset_definitions" add constraint "prepackaged_dataset_definitions_pkey" PRIMARY KEY using index "prepackaged_dataset_definitions_pkey";
alter table "public"."prepackaged_dataset_versions" add constraint "prepackaged_dataset_versions_pkey" PRIMARY KEY using index "prepackaged_dataset_versions_pkey";
alter table "public"."prepackaged_dataset_download_grants" add constraint "prepackaged_dataset_download_grants_pkey" PRIMARY KEY using index "prepackaged_dataset_download_grants_pkey";

alter table "public"."prepackaged_dataset_versions" add constraint "prepackaged_dataset_versions_definition_id_fkey" FOREIGN KEY (definition_id) REFERENCES prepackaged_dataset_definitions(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;
alter table "public"."prepackaged_dataset_versions" validate constraint "prepackaged_dataset_versions_definition_id_fkey";

alter table "public"."prepackaged_dataset_download_grants" add constraint "prepackaged_dataset_download_grants_version_id_fkey" FOREIGN KEY (version_id) REFERENCES prepackaged_dataset_versions(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;
alter table "public"."prepackaged_dataset_download_grants" validate constraint "prepackaged_dataset_download_grants_version_id_fkey";

alter table "public"."prepackaged_dataset_download_grants" add constraint "prepackaged_dataset_download_grants_user_id_fkey" FOREIGN KEY (user_id) REFERENCES auth.users(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;
alter table "public"."prepackaged_dataset_download_grants" validate constraint "prepackaged_dataset_download_grants_user_id_fkey";

alter table "public"."prepackaged_dataset_download_grants" add constraint "prepackaged_dataset_download_grants_validation_count_check" CHECK (validation_count >= 0) not valid;
alter table "public"."prepackaged_dataset_download_grants" validate constraint "prepackaged_dataset_download_grants_validation_count_check";

grant select on table "public"."prepackaged_dataset_definitions" to "authenticated";
grant select on table "public"."prepackaged_dataset_versions" to "authenticated";
grant select on table "public"."prepackaged_dataset_download_grants" to "authenticated";
grant select on table "public"."prepackaged_dataset_definitions" to "anon";
grant select on table "public"."prepackaged_dataset_versions" to "anon";
grant all on table "public"."prepackaged_dataset_definitions" to "service_role";
grant all on table "public"."prepackaged_dataset_versions" to "service_role";
grant all on table "public"."prepackaged_dataset_download_grants" to "service_role";

create policy "Anyone can read active prepackaged definitions"
on "public"."prepackaged_dataset_definitions"
as permissive
for select
to anon, authenticated
using (is_active = true);

create policy "Anyone can read available prepackaged versions"
on "public"."prepackaged_dataset_versions"
as permissive
for select
to anon, authenticated
using (
    status = 'available'
    and exists (
        select 1
        from prepackaged_dataset_definitions definition
        where definition.id = prepackaged_dataset_versions.definition_id
          and definition.is_active = true
    )
);

create policy "Users can read own prepackaged download grants"
on "public"."prepackaged_dataset_download_grants"
as permissive
for select
to authenticated
using (auth.uid() = user_id);

