            '{"dataset_name":"standing-deadwood-aerial-global-conservative","package_name":"standing-deadwood-aerial-global-conservative_2026.04.17","version":"2026.04.17","used_dataset_count":1315}'::jsonb,
            null::text
        ),
        (
            'image-tiles-1024-global-aerial-sampled-20-random',
            '2026.04.17',
            'image-tiles-1024-global-aerial-sampled-20-random_2026.04.17.zip',
